use anyhow::{Context, Result};
use std::collections::BTreeMap;
use tree_sitter::{Node, Parser};

use crate::cfg::{CfgNodeKind, ControlFlowGraph, FunctionParam, ResourceKind};
use crate::extractors::ir::{
    build_declaration_props as ir_build_declaration_props,
    build_entry_props as ir_build_entry_props,
    build_expression_statement_props as ir_build_expression_statement_props,
    build_return_props as ir_build_return_props, ir_as_simple_ident, ir_call_callee_args,
};
use crate::extractors::LanguageExtractor;
use crate::source_map::SourceSpan;

pub struct JavaExtractor;

impl LanguageExtractor for JavaExtractor {
    fn language_id(&self) -> &str {
        "java"
    }

    fn file_extensions(&self) -> &[&str] {
        &[".java"]
    }

    fn extract(&self, source: &str, file_path: &str) -> Result<Vec<ControlFlowGraph>> {
        let mut parser = Parser::new();
        let language = tree_sitter_java::LANGUAGE.into();
        parser
            .set_language(&language)
            .context("failed to set Java grammar")?;

        let tree = parser
            .parse(source, None)
            .context("failed to parse Java source")?;

        let root = tree.root_node();
        let mut cfgs = Vec::new();

        extract_java_methods(&root, source, file_path, &mut cfgs)?;

        Ok(cfgs)
    }
}

fn extract_java_methods(
    node: &Node,
    source: &str,
    file_path: &str,
    cfgs: &mut Vec<ControlFlowGraph>,
) -> Result<()> {
    if node.kind() == "method_declaration" || node.kind() == "constructor_declaration" {
        let name = node
            .child_by_field_name("name")
            .map(|n| node_text(n, source))
            .unwrap_or_else(|| "anonymous".to_string());

        let cfg = extract_java_method_cfg(node, source, file_path, &name)?;
        cfgs.push(cfg);
    }

    for i in 0..node.child_count() {
        if let Some(child) = node.child(i) {
            extract_java_methods(&child, source, file_path, cfgs)?;
        }
    }

    Ok(())
}

fn extract_java_method_cfg(
    method_node: &Node,
    source: &str,
    file_path: &str,
    name: &str,
) -> Result<ControlFlowGraph> {
    let mut cfg =
        ControlFlowGraph::new(name.to_string(), "java".to_string(), file_path.to_string());

    // Extract Java method signature.
    if let Some(params_node) = method_node.child_by_field_name("parameters") {
        for i in 0..params_node.child_count() {
            if let Some(child) = params_node.child(i) {
                if child.kind() == "formal_parameter" || child.kind() == "spread_parameter" {
                    let name = child
                        .child_by_field_name("name")
                        .map(|n| node_text(n, source))
                        .unwrap_or_default();
                    let type_ann = child
                        .child_by_field_name("type")
                        .map(|n| node_text(n, source));
                    let is_variadic = child.kind() == "spread_parameter";
                    if !name.is_empty() {
                        cfg.signature.params.push(FunctionParam {
                            name,
                            type_annotation: type_ann,
                            default_value: None,
                            is_variadic,
                            semantic_type: Default::default(),
                        });
                    }
                }
            }
        }
    }
    // Return type.
    if let Some(ret_type) = method_node.child_by_field_name("type") {
        cfg.signature.return_type = Some(node_text(ret_type, source));
    }

    let entry_props = ir_build_entry_props(&cfg.signature.params);
    let entry = cfg.add_node_with_props(
        CfgNodeKind::Entry {
            name: name.to_string(),
        },
        SourceSpan::from_tree_sitter(file_path, method_node),
        format!("method {name}"),
        entry_props,
    );
    cfg.entry = entry;

    let body = method_node
        .child_by_field_name("body")
        .unwrap_or(*method_node);

    let last = extract_java_body(&body, source, file_path, &mut cfg, entry)?;

    if let Some(last_id) = last {
        if !matches!(cfg.nodes[last_id].kind, CfgNodeKind::Return) {
            let ret = cfg.add_node(
                CfgNodeKind::Return,
                SourceSpan::from_tree_sitter(file_path, &body),
                "implicit return".to_string(),
            );
            cfg.add_edge(last_id, ret, None);
            cfg.exits.push(ret);
        }
    } else {
        let ret = cfg.add_node(
            CfgNodeKind::Return,
            SourceSpan::from_tree_sitter(file_path, &body),
            "implicit return".to_string(),
        );
        cfg.add_edge(entry, ret, None);
        cfg.exits.push(ret);
    }

    Ok(cfg)
}

fn extract_java_body(
    body: &Node,
    source: &str,
    file_path: &str,
    cfg: &mut ControlFlowGraph,
    predecessor: usize,
) -> Result<Option<usize>> {
    let mut current = predecessor;
    let body_is_container = is_java_statement_container(body);
    let child_count = if body_is_container {
        body.child_count()
    } else {
        1
    };

    for i in 0..child_count {
        let child = match if body_is_container {
            body.child(i)
        } else {
            Some(*body)
        } {
            Some(c) => c,
            None => continue,
        };

        match child.kind() {
            "if_statement" => {
                let has_else = child.child_by_field_name("alternative").is_some();
                let branch = cfg.add_node_with_props(
                    CfgNodeKind::Branch {
                        exhaustive: has_else,
                    },
                    SourceSpan::from_tree_sitter(file_path, &child),
                    node_text_truncated(&child, source, 40),
                    build_condition_props_java(&child, source),
                );
                cfg.add_edge(current, branch, None);

                let merge = cfg.add_node(
                    CfgNodeKind::Merge,
                    SourceSpan::from_tree_sitter(file_path, &child),
                    "if merge".to_string(),
                );

                if let Some(consequence) = child.child_by_field_name("consequence") {
                    let then_end = extract_java_body(&consequence, source, file_path, cfg, branch)?;
                    if let Some(te) = then_end {
                        cfg.add_edge(te, merge, None);
                    }
                }

                if let Some(alternative) = child.child_by_field_name("alternative") {
                    let else_end = extract_java_body(&alternative, source, file_path, cfg, branch)?;
                    if let Some(ee) = else_end {
                        cfg.add_edge(ee, merge, None);
                    }
                } else {
                    cfg.add_edge(branch, merge, Some("no-else".into()));
                }

                current = merge;
            }

            "switch_expression" | "switch_statement" => {
                let branch = cfg.add_node_with_props(
                    CfgNodeKind::Branch { exhaustive: false },
                    SourceSpan::from_tree_sitter(file_path, &child),
                    node_text_truncated(&child, source, 40),
                    build_condition_props_java(&child, source),
                );
                cfg.add_edge(current, branch, None);

                let merge = cfg.add_node(
                    CfgNodeKind::Merge,
                    SourceSpan::from_tree_sitter(file_path, &child),
                    "switch merge".to_string(),
                );

                if let Some(switch_body) = child.child_by_field_name("body") {
                    for j in 0..switch_body.child_count() {
                        if let Some(case) = switch_body.child(j) {
                            if case.kind() == "switch_block_statement_group"
                                || case.kind() == "switch_rule"
                            {
                                let case_end =
                                    extract_java_body(&case, source, file_path, cfg, branch)?;
                                if let Some(ce) = case_end {
                                    cfg.add_edge(ce, merge, None);
                                }
                            }
                        }
                    }
                }

                current = merge;
            }

            "assert_statement" => {
                let branch = cfg.add_node_with_props(
                    CfgNodeKind::Branch { exhaustive: false },
                    SourceSpan::from_tree_sitter(file_path, &child),
                    node_text_truncated(&child, source, 40),
                    build_condition_props_java(&child, source),
                );
                cfg.add_edge(current, branch, None);
                let merge = cfg.add_node(
                    CfgNodeKind::Merge,
                    SourceSpan::from_tree_sitter(file_path, &child),
                    "assert merge".to_string(),
                );
                cfg.add_edge(branch, merge, None);
                current = merge;
            }

            "for_statement" | "enhanced_for_statement" => {
                let bounded = child.kind() == "enhanced_for_statement";

                // C-style `for (int i = 0; …; …)` doesn't bind `i` into the
                // body scope unless we materialize the init as a synthetic
                // Statement before the Loop. tree-sitter-java exposes the
                // init via the `init` field — for the canonical
                // `local_variable_declaration` shape we reuse the same
                // property builder as a top-level local decl so gnexec sees
                // identical `bind`/`expr` shape (and `i` is bound when the
                // body executes). Multiple comma-separated `init`s and the
                // `enhanced_for_statement` (`for (T x : iter)`) shape are
                // not yet emitted — those go through the existing Loop arm
                // unchanged.
                if child.kind() == "for_statement" {
                    if let Some(init_node) = child.child_by_field_name("init") {
                        if init_node.kind() == "local_variable_declaration" {
                            let init_props =
                                build_local_variable_declaration_props_java(&init_node, source);
                            let init_stmt = cfg.add_node_with_props(
                                CfgNodeKind::Statement,
                                SourceSpan::from_tree_sitter(file_path, &init_node),
                                node_text_truncated(&init_node, source, 60),
                                init_props,
                            );
                            cfg.add_edge(current, init_stmt, None);
                            current = init_stmt;
                        }
                    }
                }

                let loop_props = if child.kind() == "enhanced_for_statement" {
                    build_enhanced_for_props_java(&child, source)
                } else {
                    BTreeMap::new()
                };
                let loop_node = cfg.add_node_with_props(
                    CfgNodeKind::Loop { bounded },
                    SourceSpan::from_tree_sitter(file_path, &child),
                    node_text_truncated(&child, source, 40),
                    loop_props,
                );
                cfg.add_edge(current, loop_node, None);

                if let Some(loop_body) = child.child_by_field_name("body") {
                    let body_end =
                        extract_java_body(&loop_body, source, file_path, cfg, loop_node)?;
                    if let Some(be) = body_end {
                        cfg.add_edge(be, loop_node, Some("back".into()));
                    }
                }

                let exit = cfg.add_node(
                    CfgNodeKind::Merge,
                    SourceSpan::from_tree_sitter(file_path, &child),
                    "for exit".to_string(),
                );
                cfg.add_edge(loop_node, exit, Some("exit".into()));
                current = exit;
            }

            "while_statement" | "do_statement" => {
                let loop_node = cfg.add_node(
                    CfgNodeKind::Loop { bounded: false },
                    SourceSpan::from_tree_sitter(file_path, &child),
                    node_text_truncated(&child, source, 40),
                );
                cfg.add_edge(current, loop_node, None);

                if let Some(loop_body) = child.child_by_field_name("body") {
                    let body_end =
                        extract_java_body(&loop_body, source, file_path, cfg, loop_node)?;
                    if let Some(be) = body_end {
                        cfg.add_edge(be, loop_node, Some("back".into()));
                    }
                }

                let exit = cfg.add_node(
                    CfgNodeKind::Merge,
                    SourceSpan::from_tree_sitter(file_path, &child),
                    "loop exit".to_string(),
                );
                cfg.add_edge(loop_node, exit, Some("exit".into()));
                current = exit;
            }

            "try_statement" => {
                let try_entry = cfg.add_node(
                    CfgNodeKind::TryEntry,
                    SourceSpan::from_tree_sitter(file_path, &child),
                    "try".to_string(),
                );
                cfg.add_edge(current, try_entry, None);

                let merge = cfg.add_node(
                    CfgNodeKind::Merge,
                    SourceSpan::from_tree_sitter(file_path, &child),
                    "try merge".to_string(),
                );

                // Try body.
                if let Some(try_body) = child.child_by_field_name("body") {
                    let try_end = extract_java_body(&try_body, source, file_path, cfg, try_entry)?;
                    if let Some(te) = try_end {
                        cfg.add_edge(te, merge, None);
                    }
                }

                // Catch clauses.
                for j in 0..child.child_count() {
                    if let Some(handler) = child.child(j) {
                        if handler.kind() == "catch_clause" {
                            let catch_node = cfg.add_node(
                                CfgNodeKind::CatchHandler,
                                SourceSpan::from_tree_sitter(file_path, &handler),
                                "catch".to_string(),
                            );
                            cfg.add_exceptional_edge(try_entry, catch_node, Some("error".into()));

                            if let Some(catch_body) = handler.child_by_field_name("body") {
                                let catch_end = extract_java_body(
                                    &catch_body,
                                    source,
                                    file_path,
                                    cfg,
                                    catch_node,
                                )?;
                                if let Some(ce) = catch_end {
                                    cfg.add_edge(ce, merge, None);
                                }
                            }
                        }
                    }
                }

                // Finally.
                if let Some(finalizer) = child.child_by_field_name("finally") {
                    let finally_node = cfg.add_node(
                        CfgNodeKind::FinallyHandler,
                        SourceSpan::from_tree_sitter(file_path, &finalizer),
                        "finally".to_string(),
                    );
                    cfg.add_edge(merge, finally_node, None);

                    let finally_end =
                        extract_java_body(&finalizer, source, file_path, cfg, finally_node)?;
                    current = finally_end.unwrap_or(finally_node);
                } else {
                    current = merge;
                }
            }

            "try_with_resources_statement" => {
                // try-with-resources = acquire + body + implicit release.
                let acquire = cfg.add_node(
                    CfgNodeKind::ResourceAcquire {
                        resource_kind: ResourceKind::Generic("auto_closeable".to_string()),
                    },
                    SourceSpan::from_tree_sitter(file_path, &child),
                    node_text_truncated(&child, source, 40),
                );
                cfg.add_edge(current, acquire, None);

                let merge = cfg.add_node(
                    CfgNodeKind::Merge,
                    SourceSpan::from_tree_sitter(file_path, &child),
                    "try-with-resources merge".to_string(),
                );

                if let Some(try_body) = child.child_by_field_name("body") {
                    let body_end = extract_java_body(&try_body, source, file_path, cfg, acquire)?;
                    if let Some(be) = body_end {
                        let release = cfg.add_node(
                            CfgNodeKind::ResourceRelease {
                                resource_kind: ResourceKind::Generic("auto_closeable".to_string()),
                            },
                            SourceSpan::from_tree_sitter(file_path, &child),
                            "auto-close".to_string(),
                        );
                        cfg.add_edge(be, release, None);
                        cfg.add_edge(release, merge, None);
                    }
                }

                current = merge;
            }

            "synchronized_statement" => {
                let lock = cfg.add_node(
                    CfgNodeKind::LockAcquire { lock_id: None },
                    SourceSpan::from_tree_sitter(file_path, &child),
                    node_text_truncated(&child, source, 40),
                );
                cfg.add_edge(current, lock, None);

                if let Some(sync_body) = child.child_by_field_name("body") {
                    let body_end = extract_java_body(&sync_body, source, file_path, cfg, lock)?;
                    if let Some(be) = body_end {
                        let unlock = cfg.add_node(
                            CfgNodeKind::LockRelease { lock_id: None },
                            SourceSpan::from_tree_sitter(file_path, &child),
                            "sync exit".to_string(),
                        );
                        cfg.add_edge(be, unlock, None);
                        current = unlock;
                    }
                }
            }

            "return_statement" => {
                let extra = build_return_props_java(&child, source);
                let ret = cfg.add_node_with_props(
                    CfgNodeKind::Return,
                    SourceSpan::from_tree_sitter(file_path, &child),
                    node_text_truncated(&child, source, 60),
                    extra,
                );
                cfg.add_edge(current, ret, None);
                cfg.exits.push(ret);
                return Ok(Some(ret));
            }

            "throw_statement" => {
                let stmt = cfg.add_node(
                    CfgNodeKind::Return,
                    SourceSpan::from_tree_sitter(file_path, &child),
                    node_text_truncated(&child, source, 60),
                );
                cfg.add_edge(current, stmt, None);
                cfg.exits.push(stmt);
                return Ok(Some(stmt));
            }

            "local_variable_declaration" | "expression_statement" => {
                let node_kind = classify_java_statement(&child, source);
                let extra = if child.kind() == "local_variable_declaration" {
                    build_local_variable_declaration_props_java(&child, source)
                } else {
                    build_expression_statement_props_java(&child, source)
                };
                let stmt = cfg.add_node_with_props(
                    node_kind,
                    SourceSpan::from_tree_sitter(file_path, &child),
                    node_text_truncated(&child, source, 60),
                    extra,
                );
                cfg.add_edge(current, stmt, None);
                current = stmt;
            }

            "comment" | "line_comment" | "block_comment" | "{" | "}" | ";" => {}

            _ => {
                let stmt = cfg.add_node(
                    CfgNodeKind::Statement,
                    SourceSpan::from_tree_sitter(file_path, &child),
                    node_text_truncated(&child, source, 60),
                );
                cfg.add_edge(current, stmt, None);
                current = stmt;
            }
        }
    }

    Ok(Some(current))
}

fn classify_java_statement(node: &Node, source: &str) -> CfgNodeKind {
    let text = node_text(*node, source);

    // Resource patterns.
    if text.contains("new FileInputStream")
        || text.contains("new FileOutputStream")
        || text.contains("new BufferedReader")
        || text.contains("Files.newInputStream")
    {
        return CfgNodeKind::ResourceAcquire {
            resource_kind: ResourceKind::File,
        };
    }
    if text.contains("DriverManager.getConnection")
        || text.contains("DataSource.getConnection")
        || text.contains(".getConnection(")
    {
        return CfgNodeKind::ResourceAcquire {
            resource_kind: ResourceKind::Connection,
        };
    }
    if text.contains(".close()") {
        return CfgNodeKind::ResourceRelease {
            resource_kind: ResourceKind::Generic("resource".to_string()),
        };
    }

    // Thread spawn -- only actual threading primitives.
    // .start() alone is too broad (matches Lifecycle.start(), Observation.start(), etc.)
    if text.contains("new Thread(")
        || text.contains("executor.submit(")
        || text.contains("executor.execute(")
        || text.contains("CompletableFuture.supplyAsync(")
        || text.contains("CompletableFuture.runAsync(")
    {
        return CfgNodeKind::ConcurrentSpawn;
    }

    // Join -- only actual synchronization, not generic .get().
    if text.contains("thread.join()")
        || text.contains("Thread.join()")
        || text.contains(".get(") && (text.contains("Future") || text.contains("CompletableFuture"))
    {
        return CfgNodeKind::SyncJoin;
    }

    CfgNodeKind::Statement
}

fn node_text(node: Node, source: &str) -> String {
    source[node.start_byte()..node.end_byte()].to_string()
}

fn node_text_truncated(node: &Node, source: &str, max: usize) -> String {
    let full = &source[node.start_byte()..node.end_byte()];
    let first_line = full.lines().next().unwrap_or(full);
    if first_line.len() > max {
        let end = first_line
            .char_indices()
            .nth(max)
            .map(|(i, _)| i)
            .unwrap_or(first_line.len());
        format!("{}...", &first_line[..end])
    } else {
        first_line.to_string()
    }
}

fn is_java_statement_container(node: &Node) -> bool {
    matches!(
        node.kind(),
        "program" | "block" | "switch_block" | "switch_block_statement_group" | "switch_rule"
    )
}

// ─────────────────────────────────────────────────────────────────────────────
// Semantic expression IR for orchestration mode.
//
// Mirrors the TypeScript / Python extractors. Walks tree-sitter-java nodes
// and emits the canonical JSON IR shape so downstream walkers (notably
// gnexec) can evaluate without re-parsing source. Unrecognised shapes fall
// back to `{ "kind": "raw", "text": <source> }`.
// ─────────────────────────────────────────────────────────────────────────────

/// Build orchestration-only properties for a Java `return_statement`.
fn build_return_props_java(node: &Node, source: &str) -> BTreeMap<String, String> {
    let mut cursor = node.walk();
    let expr = node.named_children(&mut cursor).find(|c| !is_java_skip(c));
    let Some(expr_node) = expr else {
        return BTreeMap::new();
    };
    let ir = java_node_to_ir(&expr_node, source);
    let mut props = ir_build_return_props(ir.clone());
    if let Some((callee, args)) = ir_call_callee_args(&ir) {
        props.insert("callee".to_string(), callee);
        if let Ok(args_json) = serde_json::to_string(&args) {
            props.insert("args".to_string(), args_json);
        }
    }
    props
}

/// Build orchestration-only properties for Java branch conditions.
fn build_condition_props_java(node: &Node, source: &str) -> BTreeMap<String, String> {
    let cond = node
        .child_by_field_name("condition")
        .or_else(|| node.child_by_field_name("value"));
    let Some(cond) = cond else {
        return BTreeMap::new();
    };
    let ir = java_node_to_ir(&cond, source);
    let mut props = BTreeMap::new();
    if let Ok(s) = serde_json::to_string(&ir) {
        props.insert("expr".to_string(), s);
    }
    props
}

fn build_enhanced_for_props_java(node: &Node, source: &str) -> BTreeMap<String, String> {
    let mut props = BTreeMap::new();
    if let Some(name) = node
        .child_by_field_name("name")
        .map(|n| node_text(n, source))
        .filter(|s| !s.is_empty())
    {
        props.insert("bind".to_string(), name);
    }
    if let Some(value) = node.child_by_field_name("value") {
        let iter_ir = java_node_to_ir(&value, source);
        if let Ok(s) = serde_json::to_string(&iter_ir) {
            props.insert("iter".to_string(), s);
        }
    }
    props
}

/// Build orchestration-only properties for a Java `expression_statement`.
fn build_expression_statement_props_java(node: &Node, source: &str) -> BTreeMap<String, String> {
    let mut cursor = node.walk();
    let inner = node.named_children(&mut cursor).find(|c| !is_java_skip(c));
    let Some(inner) = inner else {
        return BTreeMap::new();
    };

    if inner.kind() == "assignment_expression" {
        let mut props = BTreeMap::new();
        if let Some(left) = inner.child_by_field_name("left") {
            let bind_ir = java_node_to_ir(&left, source);
            if let Some(name) = ir_as_simple_ident(&bind_ir) {
                props.insert("bind".to_string(), name);
            } else if let Ok(s) = serde_json::to_string(&bind_ir) {
                props.insert("bind_target".to_string(), s);
            }
        }
        if let Some(right) = inner.child_by_field_name("right") {
            let value_ir = java_node_to_ir(&right, source);
            if let Ok(s) = serde_json::to_string(&value_ir) {
                props.insert("expr".to_string(), s);
            }
            if let Some((callee, args)) = ir_call_callee_args(&value_ir) {
                props.insert("callee".to_string(), callee);
                if let Ok(args_json) = serde_json::to_string(&args) {
                    props.insert("args".to_string(), args_json);
                }
            }
        }
        return props;
    }

    let ir = java_node_to_ir(&inner, source);
    ir_build_expression_statement_props(ir, None, None)
}

/// Build orchestration-only properties for a Java `local_variable_declaration`.
/// Multiple declarators (`int a = 1, b = 2`) collapse to the first declarator.
fn build_local_variable_declaration_props_java(
    node: &Node,
    source: &str,
) -> BTreeMap<String, String> {
    let mut cursor = node.walk();
    let declarator = node
        .children_by_field_name("declarator", &mut cursor)
        .next();
    let Some(declarator) = declarator else {
        return BTreeMap::new();
    };
    let bind_name = declarator
        .child_by_field_name("name")
        .map(|n| node_text(n, source));
    let value_ir = declarator
        .child_by_field_name("value")
        .map(|n| java_node_to_ir(&n, source));

    match (bind_name, value_ir) {
        (Some(name), Some(v_ir)) => ir_build_declaration_props(&name, v_ir),
        (Some(name), None) => {
            let mut props = BTreeMap::new();
            props.insert("bind".to_string(), name);
            props
        }
        (None, value_ir_opt) => {
            let mut props = BTreeMap::new();
            if let Some(v_ir) = value_ir_opt {
                if let Ok(s) = serde_json::to_string(&v_ir) {
                    props.insert("expr".to_string(), s);
                }
                if let Some((callee, args)) = ir_call_callee_args(&v_ir) {
                    props.insert("callee".to_string(), callee);
                    if let Ok(args_json) = serde_json::to_string(&args) {
                        props.insert("args".to_string(), args_json);
                    }
                }
            }
            props
        }
    }
}

/// Helper to find the ultimate receiver of a chained append call, e.g. `sb` in `sb.append(a).append(b)`.
/// Returns the IR for the root if it's a valid gnexec assignment target (ident, member, index).
fn find_java_append_root(node: &Node, source: &str) -> Option<serde_json::Value> {
    let mut current = *node;
    loop {
        if current.kind() == "method_invocation" {
            let name_text = current
                .child_by_field_name("name")
                .map(|n| node_text(n, source))
                .unwrap_or_default();
            if name_text == "append" {
                if let Some(obj) = current.child_by_field_name("object") {
                    current = obj;
                    continue;
                }
            }
        }
        let kind = current.kind();
        if kind == "identifier" || kind == "field_access" || kind == "array_access" {
            return Some(java_node_to_ir(&current, source));
        }
        return None;
    }
}

/// Convert a tree-sitter-java node into the orchestration IR.
fn java_node_to_ir(node: &Node, source: &str) -> serde_json::Value {
    use serde_json::{json, Number, Value};
    let kind = node.kind();
    match kind {
        "decimal_integer_literal"
        | "hex_integer_literal"
        | "octal_integer_literal"
        | "binary_integer_literal" => {
            let raw = node_text(*node, source);
            let cleaned = raw.trim_end_matches(['L', 'l']).replace('_', "");
            let value = if let Ok(i) = cleaned.parse::<i64>() {
                Value::Number(Number::from(i))
            } else if let Some(stripped) = cleaned
                .strip_prefix("0x")
                .or_else(|| cleaned.strip_prefix("0X"))
            {
                i64::from_str_radix(stripped, 16)
                    .ok()
                    .map(|n| Value::Number(Number::from(n)))
                    .unwrap_or(Value::String(raw.clone()))
            } else if let Some(stripped) = cleaned
                .strip_prefix("0b")
                .or_else(|| cleaned.strip_prefix("0B"))
            {
                i64::from_str_radix(stripped, 2)
                    .ok()
                    .map(|n| Value::Number(Number::from(n)))
                    .unwrap_or(Value::String(raw.clone()))
            } else {
                Value::String(raw.clone())
            };
            json!({ "kind": "literal", "value": value })
        }
        "decimal_floating_point_literal" | "hex_floating_point_literal" => {
            let raw = node_text(*node, source);
            let cleaned = raw.trim_end_matches(['f', 'F', 'd', 'D']).replace('_', "");
            let value = cleaned
                .parse::<f64>()
                .ok()
                .and_then(Number::from_f64)
                .map(Value::Number)
                .unwrap_or(Value::String(raw));
            json!({ "kind": "literal", "value": value })
        }
        "true" => json!({ "kind": "literal", "value": true }),
        "false" => json!({ "kind": "literal", "value": false }),
        "null_literal" => json!({ "kind": "literal", "value": Value::Null }),
        "string_literal" => {
            let s = java_string_literal_value(node, source);
            json!({ "kind": "literal", "value": s })
        }
        "character_literal" => json!({ "kind": "literal", "value": node_text(*node, source) }),
        "identifier" | "type_identifier" => {
            json!({ "kind": "ident", "name": node_text(*node, source) })
        }
        "this" => json!({ "kind": "ident", "name": "this" }),
        "super" => json!({ "kind": "ident", "name": "super" }),
        "parenthesized_expression" => {
            let mut cursor = node.walk();
            for child in node.named_children(&mut cursor) {
                if !is_java_skip(&child) {
                    return java_node_to_ir(&child, source);
                }
            }
            json!({ "kind": "raw", "text": node_text(*node, source) })
        }
        "field_access" => {
            let obj = node
                .child_by_field_name("object")
                .map(|n| java_node_to_ir(&n, source))
                .unwrap_or(Value::Null);
            let prop = node
                .child_by_field_name("field")
                .map(|n| node_text(n, source))
                .unwrap_or_default();
            json!({ "kind": "member", "obj": obj, "prop": prop })
        }
        "array_access" => {
            let obj = node
                .child_by_field_name("array")
                .map(|n| java_node_to_ir(&n, source))
                .unwrap_or(Value::Null);
            let key = node
                .child_by_field_name("index")
                .map(|n| java_node_to_ir(&n, source))
                .unwrap_or(Value::Null);
            json!({ "kind": "index", "obj": obj, "key": key })
        }
        "method_invocation" => {
            let name_text = node
                .child_by_field_name("name")
                .map(|n| node_text(n, source))
                .unwrap_or_default();
            let callee_value: Value = match node.child_by_field_name("object") {
                Some(obj) => {
                    let obj_ir = java_node_to_ir(&obj, source);
                    json!({ "kind": "member", "obj": obj_ir, "prop": name_text })
                }
                None => Value::String(name_text.clone()),
            };
            let mut args: Vec<Value> = Vec::new();
            if let Some(args_node) = node.child_by_field_name("arguments") {
                let mut cursor = args_node.walk();
                for child in args_node.named_children(&mut cursor) {
                    if is_java_skip(&child) {
                        continue;
                    }
                    args.push(java_node_to_ir(&child, source));
                }
            }
            // Canonicalize `x.get("field")` — the idiomatic Java Map read —
            // to `member` IR (the shape TS `x.field` lowers to) when the key
            // is a plain literal field name. Property-carried walkers then
            // evaluate the access without Java Map semantics; dynamic or
            // non-field-shaped keys keep the call form.
            if name_text == "get" && node.child_by_field_name("object").is_some() {
                if let [key] = args.as_slice() {
                    if key.get("kind").and_then(|k| k.as_str()) == Some("literal") {
                        if let Some(field) = key.get("value").and_then(|v| v.as_str()) {
                            if crate::extractors::ir::is_plain_field_name(field) {
                                let obj_ir = callee_value
                                    .get("obj")
                                    .cloned()
                                    .unwrap_or(Value::Null);
                                return json!({
                                    "kind": "member",
                                    "obj": obj_ir,
                                    "prop": field
                                });
                            }
                        }
                    }
                }
            }
            let call_ir = json!({ "kind": "call", "callee": callee_value, "args": args });
            if name_text == "append" {
                if let Some(root_target) = find_java_append_root(node, source) {
                    return json!({
                        "kind": "assign",
                        "op": "=",
                        "target": root_target,
                        "value": call_ir
                    });
                }
            }
            call_ir
        }
        "object_creation_expression" => {
            // Mirror tree-sitter-typescript's `new_expression` shape so the
            // shared gnexec `kind:"new"` arm dispatches Java constructor
            // calls through `eval_new_by_name` (Date/URL/Map/Set/user
            // classes) instead of the `kind:"call"` arm. Callee is emitted
            // as a `kind:"ident"` IR node — gnexec reads `callee.name` to
            // resolve the constructor.
            let type_text = node
                .child_by_field_name("type")
                .map(|n| java_constructor_name(&node_text(n, source)))
                .unwrap_or_default();
            let mut args: Vec<Value> = Vec::new();
            if let Some(args_node) = node.child_by_field_name("arguments") {
                let mut cursor = args_node.walk();
                for child in args_node.named_children(&mut cursor) {
                    if is_java_skip(&child) {
                        continue;
                    }
                    args.push(java_node_to_ir(&child, source));
                }
            }
            json!({
                "kind": "new",
                "callee": { "kind": "ident", "name": type_text },
                "args": args
            })
        }
        "binary_expression" => {
            let lhs = node
                .child_by_field_name("left")
                .map(|n| java_node_to_ir(&n, source))
                .unwrap_or(Value::Null);
            let rhs = node
                .child_by_field_name("right")
                .map(|n| java_node_to_ir(&n, source))
                .unwrap_or(Value::Null);
            let op = node
                .child_by_field_name("operator")
                .map(|n| node_text(n, source))
                .unwrap_or_default();
            // Canonicalize provably-string `+` chains (`"hello:" + name`) to
            // `template` IR — Java string concatenation is TS's template
            // literal in different clothing. Numeric/ident-only chains keep
            // the plain binary form.
            if op == "+" {
                if let Some(template) =
                    crate::extractors::ir::concat_chain_to_template(&lhs, &rhs)
                {
                    return template;
                }
            }
            json!({ "kind": "binary", "op": op, "lhs": lhs, "rhs": rhs })
        }
        "unary_expression" => {
            let arg = node
                .child_by_field_name("operand")
                .map(|n| java_node_to_ir(&n, source))
                .unwrap_or(Value::Null);
            let op = node
                .child_by_field_name("operator")
                .map(|n| node_text(n, source))
                .unwrap_or_default();
            json!({ "kind": "unary", "op": op, "arg": arg })
        }
        "ternary_expression" => {
            let cond = node
                .child_by_field_name("condition")
                .map(|n| java_node_to_ir(&n, source))
                .unwrap_or(Value::Null);
            let cons = node
                .child_by_field_name("consequence")
                .map(|n| java_node_to_ir(&n, source))
                .unwrap_or(Value::Null);
            let alt = node
                .child_by_field_name("alternative")
                .map(|n| java_node_to_ir(&n, source))
                .unwrap_or(Value::Null);
            json!({ "kind": "ternary", "cond": cond, "cons": cons, "alt": alt })
        }
        "instanceof_expression" => {
            let lhs = node
                .child_by_field_name("left")
                .or_else(|| node.child_by_field_name("value"))
                .map(|n| java_node_to_ir(&n, source))
                .unwrap_or(Value::Null);
            let rhs = node
                .child_by_field_name("right")
                .or_else(|| node.child_by_field_name("type"))
                .map(|n| java_node_to_ir(&n, source))
                .unwrap_or_else(|| {
                    let mut cursor = node.walk();
                    node.named_children(&mut cursor)
                        .filter(|c| !is_java_skip(c))
                        .last()
                        .map(|n| java_node_to_ir(&n, source))
                        .unwrap_or(Value::Null)
                });
            json!({ "kind": "binary", "op": "instanceof", "lhs": lhs, "rhs": rhs })
        }
        "array_creation_expression" => {
            if let Some(init) = node.child_by_field_name("value") {
                let mut items: Vec<Value> = Vec::new();
                let mut cursor = init.walk();
                for child in init.named_children(&mut cursor) {
                    if is_java_skip(&child) {
                        continue;
                    }
                    items.push(java_node_to_ir(&child, source));
                }
                return json!({ "kind": "array", "items": items });
            }
            json!({ "kind": "raw", "text": node_text(*node, source) })
        }
        "array_initializer" => {
            let mut items: Vec<Value> = Vec::new();
            let mut cursor = node.walk();
            for child in node.named_children(&mut cursor) {
                if is_java_skip(&child) {
                    continue;
                }
                items.push(java_node_to_ir(&child, source));
            }
            json!({ "kind": "array", "items": items })
        }
        "cast_expression" => {
            if let Some(value) = node.child_by_field_name("value") {
                return java_node_to_ir(&value, source);
            }
            json!({ "kind": "raw", "text": node_text(*node, source) })
        }
        "update_expression" => {
            let mut op = String::new();
            let mut arg_ir = Value::Null;
            let mut cursor = node.walk();
            for child in node.children(&mut cursor) {
                if !child.is_named() {
                    op = node_text(child, source);
                } else if !is_java_skip(&child) {
                    arg_ir = java_node_to_ir(&child, source);
                }
            }
            json!({ "kind": "unary", "op": op, "arg": arg_ir })
        }
        "assignment_expression" => {
            let target = node
                .child_by_field_name("left")
                .map(|n| java_node_to_ir(&n, source))
                .unwrap_or(Value::Null);
            let value = node
                .child_by_field_name("right")
                .map(|n| java_node_to_ir(&n, source))
                .unwrap_or(Value::Null);
            let op = node
                .child_by_field_name("operator")
                .map(|n| node_text(n, source))
                .unwrap_or_else(|| "=".to_string());
            json!({ "kind": "assign", "op": op, "target": target, "value": value })
        }
        "lambda_expression" => {
            let mut params: Vec<Value> = Vec::new();
            if let Some(params_node) = node.child_by_field_name("parameters") {
                if params_node.kind() == "inferred_parameters" {
                    let mut cursor = params_node.walk();
                    for child in params_node.named_children(&mut cursor) {
                        if !is_java_skip(&child) {
                            params.push(json!({ "name": node_text(child, source) }));
                        }
                    }
                } else if params_node.kind() == "formal_parameters" {
                    let mut cursor = params_node.walk();
                    for child in params_node.named_children(&mut cursor) {
                        if child.kind() == "formal_parameter" {
                            if let Some(name_node) = child.child_by_field_name("name") {
                                params.push(json!({ "name": node_text(name_node, source) }));
                            }
                        }
                    }
                } else {
                    // Single parameter without parens
                    params.push(json!({ "name": node_text(params_node, source) }));
                }
            }
            let body_raw = node
                .child_by_field_name("body")
                .map(|n| node_text(n, source))
                .unwrap_or_default();
            json!({ "kind": "lambda", "params": params, "body_raw": body_raw })
        }
        "method_reference" => {
            json!({ "kind": "ident", "name": node_text(*node, source) })
        }
        "class_literal" => {
            json!({ "kind": "literal", "value": node_text(*node, source) })
        }
        // `switch_expression` etc. fall back to raw.
        _ => json!({ "kind": "raw", "text": node_text(*node, source) }),
    }
}

/// Strip surrounding quotes from a Java string node and concatenate fragments.
fn java_string_literal_value(node: &Node, source: &str) -> String {
    let mut out = String::new();
    let mut cursor = node.walk();
    for child in node.named_children(&mut cursor) {
        match child.kind() {
            "string_fragment" | "multiline_string_fragment" | "escape_sequence" => {
                out.push_str(&node_text(child, source));
            }
            _ => {}
        }
    }
    if !out.is_empty() {
        return out;
    }
    let raw = node_text(*node, source);
    let trimmed = raw.trim();
    if trimmed.starts_with("\"\"\"") && trimmed.ends_with("\"\"\"") && trimmed.len() >= 6 {
        return trimmed[3..trimmed.len() - 3].to_string();
    }
    if trimmed.starts_with('"') && trimmed.ends_with('"') && trimmed.len() >= 2 {
        return trimmed[1..trimmed.len() - 1].to_string();
    }
    raw
}

fn java_constructor_name(type_text: &str) -> String {
    let without_generics = type_text.split('<').next().unwrap_or(type_text).trim();
    without_generics
        .rsplit('.')
        .next()
        .unwrap_or(without_generics)
        .to_string()
}

/// Skip predicate for Java AST traversal.
fn is_java_skip(node: &Node) -> bool {
    matches!(
        node.kind(),
        "line_comment" | "block_comment" | "marker_annotation" | "annotation"
    )
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn extracts_java_method() {
        let source = r#"
public class MyService {
    public void processData(byte[] data) throws Exception {
        if (data == null) {
            throw new IllegalArgumentException("null data");
        }
        try (var stream = new FileInputStream("input.txt")) {
            stream.read(data);
        } catch (IOException e) {
            log.error("failed", e);
        }
    }
}
"#;

        let extractor = JavaExtractor;
        let cfgs = extractor.extract(source, "MyService.java").unwrap();
        assert_eq!(cfgs.len(), 1);
        assert_eq!(cfgs[0].function_name, "processData");
    }

    #[test]
    fn try_with_resources_has_acquire_release() {
        let source = r#"
public class Reader {
    public String read() {
        try (var reader = new BufferedReader(new FileReader("f.txt"))) {
            return reader.readLine();
        }
    }
}
"#;

        let extractor = JavaExtractor;
        let cfgs = extractor.extract(source, "Reader.java").unwrap();
        let has_acquire = cfgs[0]
            .nodes
            .iter()
            .any(|n| matches!(n.kind, CfgNodeKind::ResourceAcquire { .. }));
        let has_release = cfgs[0]
            .nodes
            .iter()
            .any(|n| matches!(n.kind, CfgNodeKind::ResourceRelease { .. }));
        assert!(has_acquire, "try-with-resources should create acquire");
        assert!(has_release, "try-with-resources should create release");
    }
}
